/**
 * Runs a real LDAP search (and optional user bind) against the
currently saved LDAP settings so the operator can confirm
connectivity, credentials, and the AD group → role/department
mapping before relying on it for sign-in. Admin-only.

 * @summary Validate LDAP / AD configuration
 */
export const TestLdapBody = zod
  .object({
    username: zod.string().nullish(),
    password: zod.string().nullish(),
  })
  .describe(
    "Optional username\/password to fully exercise the user-bind path.\nWhen omitted, the test only validates the bind-DN credentials and\nthe search\/CA chain — useful when the operator wants to confirm\nthe server is reachable without typing a real user password.\n",
  );

export const TestLdapResponse = zod.object({
  ok: zod.boolean(),
  stage: zod
    .enum(["bind", "search", "user_bind", "mapping", "complete"])
    .describe("Which phase of the test the outcome reports on"),
  error: zod.string().nullish(),
  displayName: zod.string().nullish(),
  email: zod.string().nullish(),
  groups: zod.array(zod.string()),
  derivedRoles: zod.array(
    zod.enum([
      "ADMIN",
      "FINANCIAL_ALL",
      "FINANCIAL_INVOICE",
      "FINANCIAL_PAYMENT",
      "DEPT_MANAGER",
      "DEPT_USER",
      "GT_INVEST",
      "GT_INVEST_NOTIFICATIONS",
      "READ_ONLY_DEPT",
      "READ_ONLY_ALL",
    ]),
  ),
  derivedDepartmentCodes: zod.array(zod.string()),
  steps: zod
    .array(
      zod.object({
        name: zod.string(),
        status: zod.enum(["ok", "fail", "skip"]),
        detail: zod.string().nullish(),
        durationMs: zod.number().nullish(),
      }),
    )
    .describe(
      "Step-by-step trace of the diagnostic so the operator can see\nexactly which phase failed and the raw error message.\n",
    ),
});

/**
 * Sends a one-off test message to the supplied recipient using
either the values in the request body (so admins can validate
a config *before* saving it) or, when fields are omitted, the
currently saved SMTP settings. The saved password is reused
whenever the body omits one. Admin-only.

 * @summary Send a test email using the current SMTP settings
 */
export const TestSmtpBody = zod.object({
  to: zod.string().email().describe("Recipient email address"),
  host: zod.string().nullish(),
  port: zod.number().nullish(),
  secure: zod.boolean().nullish(),
  username: zod.string().nullish(),
  password: zod
    .string()
    .nullish()
    .describe("Optional. When omitted, the saved password is reused."),
  fromAddress: zod.string().nullish(),
});

export const TestSmtpResponse = zod.object({
  ok: zod.boolean(),
  message: zod.string().nullish(),
});

/**
 * Iterates every user with `source=LDAP`, queries the directory for
their current group memberships, and re-applies the configured
Group → Role and Group → Department mappings. Use this after
changing AD group membership (e.g. assigning a new user to the
GT Invest notifications group) so the change is reflected
immediately instead of waiting for the user to log in again.
Admin-only.

 * @summary Re-derive roles + departments from AD groups for every LDAP user
 */
export const SyncLdapRolesResponse = zod.object({
  ok: zod.boolean(),
  scanned: zod.number().describe("Number of LDAP users iterated"),
  updated: zod
    .number()
    .describe("Number of users whose roles or departments changed"),
  skipped: zod
    .number()
    .describe("Number of users skipped (no AD groups returned"),
  errors: zod.array(
    zod.object({
      username: zod.string(),
      error: zod.string(),
    }),
  ),
  message: zod.string().nullish(),
});

